class Solution:
    def checkZeroOnes(self, s):
        best = {'0': 0, '1': 0}
        cur = 0
        prev = ''
        for ch in s:
            cur = cur + 1 if ch == prev else 1
            prev = ch
            if cur > best[ch]:
                best[ch] = cur
        return best['1'] > best['0']

