var checkZeroOnes = function(s) {
    const best = {'0': 0, '1': 0};
    let cur = 0, prev = '';
    for (const ch of s) {
        cur = ch === prev ? cur + 1 : 1;
        prev = ch;
        if (cur > best[ch]) best[ch] = cur;
    }
    return best['1'] > best['0'];
